tality"}},"reverse":false},{"id":"news-cards","kind":"cards","eyebrow":{"vi":"Stories","en":"Stories"},"title":{"vi":"Ba bài viết mẫu","en":"Three sample stories"},"description":{"vi":"Mỗi card là một article record có slug và SEO riêng.","en":"Each card is an article record with its own slug and SEO."},"items":[{"href":"/tin-tuc/hold-room-workflow","eyebrow":{"vi":"News","en":"News"},"title":{"vi":"Hold room workflow","en":"Hold room workflow"},"description":{"vi":"Cách giữ phòng, expiry 30 phút và manual confirmation được thể hiện trong UI.","en":"How room holds, the 30-minute expiry, and manual confirmation appear in the UI."},"meta":[{"vi":"Workflow","en":"Workflow"},{"vi":"5 min read","en":"5 min read"},{"vi":"April 2026","en":"April 2026"}],"tone":"paper"},{"href":"/tin-tuc/deposit-qr-manual-verification","eyebrow":{"vi":"News","en":"News"},"title":{"vi":"Deposit QR and manual verification","en":"Deposit QR and manual verification"},"description":{"vi":"Bước QR, proof upload và xác minh thủ công cho phase 1 manual-first.","en":"The QR step, proof upload, and manual verification flow for phase 1."},"meta":[{"vi":"Payment","en":"Payment"},{"vi":"4 min read","en":"4 min read"},{"vi":"April 2026","en":"April 2026"}],"tone":"gold"},{"href":"/tin-tuc/member-portal-vision","eyebrow":{"vi":"News","en":"News"},"title":{"vi":"Member portal vision","en":"Member portal vision"},"description":{"vi":"Cách member portal giữ request, booking và lịch sử theo một cấu trúc gọn.","en":"How the member portal keeps requests, bookings, and history in one compact structure."},"meta":[{"vi":"Member","en":"Member"},{"vi":"6 min read","en":"6 min read"},{"vi":"April 2026","en":"April 2026"}],"tone":"ink"}]},{"id":"cta","kind":"band","eyebrow":{"vi":"Next step","en":"Next step"},"title":{"vi":"Muốn đọc các cập nhật tiếp theo của khách sạn?","en":"Want to read the hotel’s next updates?"},"description":{"vi":"Trang news giữ layout riêng để sau này nối CMS blog workflow dễ hơn.","en":"The n